function getAgentApiToken() {
  return process.env.ATHANOR_AGENT_API_TOKEN?.trim() || "";
}

function buildAgentRequestInit(init: RequestInit | undefined, timeoutMs: number): RequestInit {
  const headers = new Headers(init?.headers);

  const agentApiToken = getAgentApiToken();
  if (agentApiToken) {
    headers.set("Authorization", `Bearer ${agentApiToken}`);
  }

  return {
    ...init,
    headers,
    signal: init?.signal ?? AbortSignal.timeout(timeoutMs),
  };
}

function forwardUpstreamResponse(response: Response) {
  return new NextResponse(response.body, {
    status: response.status,
    headers: response.headers,
  });
}

