export async function proxyAgentJson(
  path: string,
  init: RequestInit | undefined,
  errorMessage: string,
  timeoutMs = 10_000
) {
  if (isDashboardFixtureMode()) {
    const fixtureResponse = await buildFixtureAgentResponse(path, init);
    if (fixtureResponse) {
      return NextResponse.json(fixtureResponse);
    }
  }

  try {
    const response = await fetch(joinUrl(config.agentServer.url, path), buildAgentRequestInit(init, timeoutMs));
    return forwardUpstreamResponse(response);
  } catch {
    return NextResponse.json({ error: errorMessage }, { status: 502 });
  }
}
